using System.Numerics;
using Mathematics.NET.NumberTheory;

namespace Mathematics.NET.UnitTests.NumberTheory;

[TestClass]
[TestCategory("Combinatorics")]
public sealed class CombinatoricsTests
{
    [TestMethod]
    [DynamicData(nameof(GetBinomialData))]
    public void Binomial(int n, int k, BigInteger expected)
    {
        var actual = Combinatorics.Binomial<BigInteger>(n, k);

        Assert.AreEqual(expected, actual);
    }

    [TestMethod]
    [DynamicData(nameof(GetMultinomialData))]
    public void Multinomial_BigInteger_ReturnsCorrectValue(int[] k, BigInteger expected)
    {
        var actual = Combinatorics.Multinomial<BigInteger>(k);

        Assert.AreEqual(expected, actual);
    }

    //
    // Helpers
    //

    public static IEnumerable<(int N, int K, BigInteger Expected)> GetBinomialData()
    {
        yield return new(8263, 3843, BigInteger.Parse(""));
    }

    public static IEnumerable<(int[] K, BigInteger Expected)> GetMultinomialData()
    {
        yield return new([3, 7, 4, 2], 14414400);
    }
}
